// // This module selects between input `in2` and a constant LOW output (1'b0) based on the value of the `sel` signal.
module top_module(
    input sel,
    input in1,
    input in2,
    output out
);wire n_sel;
    assign n_sel = ~sel;

    assign out = (n_sel & in1) | (sel & 1'b1);

endmodule
